function renderDashboard(){
  const{totalProfitToman,totalProfitAED,result}=calcAll();

  // محاسبه موجودی کل به تومان = هر ارز × موجودی × نرخ لحظه‌ای
  let totalInventoryToman=0;
  for(const [code,d] of Object.entries(result)){
    if(d.inventory>0 && rates[code]>0){
      totalInventoryToman += d.inventory * rates[code];
    }
  }

  const elT=$('pvt');
  elT.textContent=(totalProfitToman>=0?'+':'')+fN(Math.abs(totalProfitToman));
  elT.className='pv '+(totalProfitToman>=0?'pos':'neg');

  const elA=$('pvAED');
  elA.textContent=(totalProfitAED>=0?'+':'')+fN(Math.abs(totalProfitAED),2);
  elA.className='pv '+(totalProfitAED>=0?'pos':'neg');

  // موجودی کل به تومان
  const elTot=$('pvTotal');
  if(elTot) elTot.textContent=fN(Math.round(totalInventoryToman));

  // موجودی ارزهای مشخص در داشبورد
  const balGrid=$('dashBalances');
  if(balGrid){
    const show=['USD','AED','OMR','BTC'];
    balGrid.innerHTML=show.map(code=>{
      const d=result[code];
      const inv=d?d.inventory:0;
      const invToman=inv>0?(inv*rates[code]):0;
      const c=CUR[code];
      const dec=code==='BTC'?4:code==='OMR'?3:2;
      const cls=inv>0?'pos':inv<0?'neg':'neu';
      return `<div class="inv-card" style="padding:14px 16px">
        <div class="inv-header" style="margin-bottom:8px">
          <div class="inv-flag" style="font-size:1.6rem">${c.flag}</div>
          <div><div class="inv-name" style="font-size:.88rem">${c.name}</div></div>
        </div>
        <div class="inv-row"><span class="inv-label">موجودی</span>
          <span class="inv-val ${cls}">${fN(inv,dec)} ${c.unit}</span></div>
        ${invToman>0?`<div class="inv-row"><span class="inv-label">ارزش تومانی</span>
          <span class="inv-val neu" style="font-size:.78rem">${fN(Math.round(invToman))}</span></div>`:''}
      </div>`;
    }).join('');
  }
}

function renderInventory(){
  const{result}=calcAll();
  const grid=$('invGrid');
  const aedRate=rates['AED']||1;
  const cards=Object.entries(CUR).map(([code,c])=>{
    const d=result[code];
    if(d.buyAmt===0&&d.sellAmt===0) return '';
    const invC=d.inventory>0?'neu':d.inventory<0?'neg':'neu';
    const pC=d.profitToman>=0?'pos':'neg';
    const pS=d.profitToman>=0?'+':'';
    const dec=code==='BTC'?6:code==='GOLD'?3:2;
    const profitAED=d.profitToman/aedRate;
    const paC=profitAED>=0?'pos':'neg';
    const paS=profitAED>=0?'+':'';
    return `<div class="inv-card">
      <div class="inv-header"><div class="inv-flag">${c.flag}</div>
        <div><div class="inv-name">${c.name}</div><div class="inv-code">${code}</div></div></div>
      <div class="inv-row"><span class="inv-label">موجودی</span>
        <span class="inv-val ${invC}">${fN(d.inventory,dec)} ${c.unit}</span></div>
      <div class="inv-row"><span class="inv-label">کل خرید</span>
        <span class="inv-val neu">${fN(d.buyAmt,dec)} ${c.unit}</span></div>
      <div class="inv-row"><span class="inv-label">کل فروش</span>
        <span class="inv-val neu">${fN(d.sellAmt,dec)} ${c.unit}</span></div>
      <div class="inv-row"><span class="inv-label">میانگین خرید</span>
        <span class="inv-val neu">${fN(d.avgBuy)} تومان</span></div>
      <div class="inv-row"><span class="inv-label">سود / زیان (تومان)</span>
        <span class="inv-val ${pC}">${pS}${fN(Math.abs(d.profitToman))} تومان</span></div>
      <div class="inv-row"><span class="inv-label">سود / زیان (درهم)</span>
        <span class="inv-val ${paC}">${paS}${fN(Math.abs(profitAED),2)} درهم</span></div>
    </div>`;
  }).join('');
  grid.innerHTML=cards||`<div class="es"><img src="${LOGO_SRC}" alt=""/><div class="etag">WHALIXIR<br/>BY SHAMSADDIN MOLLAEI</div></div>`;
}

// ── CHART ─────────────────────────────────────────────────────────
let chartPeriod = 'monthly'; // 'daily' یا 'monthly'

function renderChart(){
  const{labels,profitToman,profitAED}=chartPeriod==='daily'?dailyData():monthlyData();
  const canvas=$('myChart');
  const isDark=document.body.classList.contains('dark');
  const gridColor=isDark?'rgba(255,255,255,.07)':' rgba(0,0,0,.07)';
  const textColor=isDark?'#90aec9':'#2c5282';

  if(chartInstance) chartInstance.destroy();

  if(!labels.length){
    canvas.getContext('2d').clearRect(0,0,canvas.width,canvas.height);
    return;
  }

  chartInstance=new Chart(canvas,{
    data:{
      labels,
      datasets:[
        {
          type:'bar',
          label:'سود تومانی',
          data:profitToman,
          backgroundColor:profitToman.map(v=>v>=0?'rgba(38,215,130,.7)':' rgba(255,82,113,.7)'),
          borderColor:profitToman.map(v=>v>=0?'#26d782':'#ff5271'),
          borderWidth:1,
          borderRadius:4,
          yAxisID:'y',
          order:2
        },
        {
          type:'line',
          label:'سود درهمی',
          data:profitAED,
          borderColor:'#f5a623',
          backgroundColor:'rgba(245,166,35,.15)',
          borderWidth:2.5,
          pointBackgroundColor:'#f5a623',
          pointRadius:4,
          tension:.35,
          fill:false,
          yAxisID:'y2',
          order:1
        }
      ]
    },
    options:{
      responsive:true,
      maintainAspectRatio:false,
      interaction:{mode:'index',intersect:false},
      plugins:{
        legend:{display:false},
        tooltip:{
          rtl:true,
          callbacks:{
            label:ctx=>{
              if(ctx.dataset.label==='سود تومانی')
                return ' '+fN(ctx.raw)+' تومان';
              return ' '+fN(ctx.raw,2)+' درهم';
            }
          }
        }
      },
      scales:{
        x:{ticks:{color:textColor,font:{family:'Vazirmatn'}},grid:{color:gridColor}},
        y:{
          position:'right',
          ticks:{color:textColor,font:{family:'Vazirmatn'},
            callback:v=>fN(v)+' ت'
          },
          grid:{color:gridColor}
        },
        y2:{
          position:'left',
          ticks:{color:'#f5a623',font:{family:'Vazirmatn'},
            callback:v=>fN(v,1)+' د'
          },
          grid:{display:false}
        }
      }
    }
  });

}

