// ── نمودار واید/تمام‌صفحه هنگام چرخش گوشی به حالت افقی ──────────────
(function initChartLandscape(){
  const canvas = $('myChart');
  if(!canvas) return;

  // جای اصلی کنواس را نگه می‌داریم تا دقیقاً برگردد سرجای خودش
  const originalParent = canvas.parentNode;
  const originalNextSibling = canvas.nextSibling;

  // کانتینر تمام‌صفحهٔ مستقل که خودمان کاملاً کنترلش می‌کنیم
  const fsHost = document.createElement('div');
  fsHost.id = 'wxChartFsHost';
  fsHost.style.cssText = `
    display:none;
    position:fixed; top:0; left:0; right:0; bottom:0;
    width:100vw; height:100vh;
    z-index:99999;
    padding:10px;
    box-sizing:border-box;
  `;
  document.body.appendChild(fsHost);

  let fsActive = false;

  function isMobileSize(){ return Math.min(window.innerWidth, window.innerHeight) <= 820; }
  function isLandscape(){
    if(window.matchMedia) return window.matchMedia('(orientation: landscape)').matches;
    return window.innerWidth > window.innerHeight;
  }

  function resetCanvasSize(){
    // هر اندازه‌ای که Chart.js قبلاً روی کنواس ست کرده پاک می‌کنیم
    canvas.style.width = '';
    canvas.style.height = '';
    canvas.removeAttribute('width');
    canvas.removeAttribute('height');
  }

  function enterFullscreen(){
    if(fsActive) return;
    fsActive = true;
    fsHost.style.background = document.body.classList.contains('dark') ? '#0f1720' : '#ffffff';
    fsHost.appendChild(canvas);
    fsHost.style.display = 'block';
    document.body.classList.add('wx-chart-fs-active');
    resetCanvasSize();
    canvas.style.width = '100%';
    canvas.style.height = '100%';
    // یک فریم صبر می‌کنیم تا اندازهٔ جدید واقعاً اعمال شده باشد، بعد نمودار را از نو می‌سازیم
    requestAnimationFrame(()=>requestAnimationFrame(renderChart));
  }

  function exitFullscreen(){
    if(!fsActive) return;
    fsActive = false;
    if(originalNextSibling && originalNextSibling.parentNode===originalParent){
      originalParent.insertBefore(canvas, originalNextSibling);
    } else {
      originalParent.appendChild(canvas);
    }
    fsHost.style.display = 'none';
    document.body.classList.remove('wx-chart-fs-active');
    resetCanvasSize();
    requestAnimationFrame(()=>requestAnimationFrame(renderChart));
  }

  function applyChartOrientation(){
    const chartTab = document.getElementById('tab-chart');
    const onChartTab = !!(chartTab && chartTab.classList.contains('active'));
    const shouldFs = isLandscape() && isMobileSize() && onChartTab;
    if(shouldFs) enterFullscreen();
    else exitFullscreen();
  }

  window.addEventListener('orientationchange', ()=>setTimeout(applyChartOrientation,250));
  window.addEventListener('resize', ()=>{
    clearTimeout(window._wxChartResizeT);
    window._wxChartResizeT = setTimeout(applyChartOrientation,150);
  });

  // وقتی تب عوض می‌شود هم چک شود (مثلاً از نمودار خارج شود)
  const origTab = window.tab;
  if(typeof origTab==='function'){
    window.tab = function(id){
      origTab(id);
      if(id==='chart') setTimeout(applyChartOrientation,120);
      else exitFullscreen();
    };
  }

  applyChartOrientation();
})();


